sql:
SELECT project_id, MAX(note_date) AS latest_note_date
FROM project_notes
GROUP BY project_id;

external_knowledge:
- The investment rounds are ranked in descending order based on the amount invested; 
A higher rank indicates a larger investment amount; 
Top 3 investment rounds imply the rounds with the largest investment amounts for each project.

; 
; Top projects imply the ones with the highest valuation within their respective industries; 
; The valuation of a project refers to its current valuation in USD.
